function guideDeepDive(profile:GuideProfile){
  const specifics=guideSpecifics[profile.id];
  if(!specifics||specifics.length!==5)throw new Error(`Swedish guide specifics missing for ${profile.id}`);
  const headings=["Arbetsscenario i praktiken","Beräkning och dimensionering","Godkännandepunkter","Drift och återbeställning","Beslutsunderlag för ledningen"];
  const frames=[
    ["Beskriv scenariot med användare, plats, belastning och tidsperiod. Markera vad som händer normalt och vad som händer vid toppbelastning eller avvikelse. Då bedöms lösningen mot verklig drift i stället för en isolerad katalogegenskap.","Tilldela varje öppen fråga en ägare och ett sista beslutsdatum. Inköp, träningsdrift, lager och leverantör kan annars göra olika antaganden om samma punkt."],
    ["Räkna med angivna enheter och visa mellanled. Vikt, antal, mått, yta, volym, cykler eller kostnad ska kunna kontrolleras av en kollega utan muntlig förklaring.","Gör en känslighetskontroll för den faktor som varierar mest. Jämför minst ett realistiskt låg-, bas- och högscenario innan budget eller artikelmix låses."],
    ["En godkännandepunkt behöver krav, metod, urval, gräns, dokument och behörig beslutsfattare. Skriv också vad som händer när resultatet ligger utanför gränsen.","Separera kritiska funktionsfel från större kommersiella fel och mindre kosmetiska avvikelser. Klassningen ska bygga på användning och avtal, inte skapas först när felet hittas."],
    ["Planera hur samma artikel kan identifieras, kompletteras, rengöras, servas och reklameras efter leverans. Produktens liv i lager och gym är en del av inköpsbeslutet.","Spara artikelversion, godkänt prov, mätdata, artwork och packinstruktion. Vid återbeställning bekräftas ändringar före materialköp så att serien inte glider obemärkt."],
    ["Sammanfatta alternativen i en sida med rekommendation, viktiga antaganden, total kostnad, huvudrisker och återstående beslut. Ledningen behöver veta vad som är verifierat och vad som fortfarande kan ändra utfallet.","Rekommendationen ska ange varför ett alternativ passar den definierade verksamheten, inte bara varför produkten verkar bäst. Lägg till stoppvillkor om prov, kostnad eller dokumentation inte når beslutad nivå."]
  ];
  const evidenceFrames=[
    "Skriv observationer som data: datum, plats, artikelversion, antal och ansvarig. Komplettera med bilder där de förklarar sammanhanget, men låt mätvärden och godkända dokument bära beslutet. Ett tydligt underlag gör det möjligt att skilja ett enstaka fel från ett återkommande processproblem.",
    "Ange alltid datakällan och om siffran är uppmätt, offererad eller uppskattad. Uppdatera beräkningen när packlista, fraktoffert eller provresultat ersätter antagandet. På så sätt ser beslutsfattaren både aktuell prognos och vilka variabler som fortfarande kan påverka den totala affären.",
    "Provresultat ska gå att härleda till exakt enhet och metod. Notera instrument, förutsättningar och eventuell osäkerhet. Om leverantör och köpare mäter olika behöver metoden harmoniseras före produktion, annars kan båda följa sin instruktion och ändå komma fram till olika beslut.",
    "Driftdata efter mottagning ger återkoppling till nästa specifikation. Registrera skador, saknade delar, slitage, användarproblem och tid för montering eller hantering per artikel och batch. Återkommande mönster prioriteras i nästa RFQ, prov eller packningsinstruktion.",
    "Bifoga den korta rekommendationen till det fullständiga underlaget. Där finns mätningar, kostnadsmodell, avvikelser och godkännanden för den som behöver granska detaljerna. Den kombinationen gör beslutet snabbt att förstå men svårt att misstolka vid order eller senare uppföljning."
  ];
  return specifics.map((specific,index)=>svText(`fordjupning-${index+1}`,headings[index],specific,...frames[index],evidenceFrames[index]));
}

export function swedishGuideVersion(profile:GuideProfile):LocalizedContentVersion{
  const slug=profile.path.split("/").pop()!;
  const index=swedishGuideProfiles.indexOf(profile);
  const images:LocalizedImage[]=[verifiedGuideImage[profile.image]??profile.image,"/assets/dumbbell-production.webp","/assets/factory-cases/packaging-area-pbf.webp"].map((src,imageIndex)=>({id:`bild-${imageIndex+1}`,src:swedishImagePath(src,slug,imageIndex),alt:imageIndex===0?`${profile.h1} – verkligt underlag`:imageIndex===1?`Verklig tillverkningsprocess kopplad till ${profile.keyword}`:"Verklig exportförpackning för gymutrustning",caption:imageIndex===0?"Befintlig PowerBaseFit-bild som stödjer guidens beslutssituation.":imageIndex===1?"Produktion används som bevis först när processen kopplas till en specifikation.":"Förpackning och pallplan påverkar både skaderisk och total kostnad."}));
  const body=[
    svAnswer("snabbt-svar","Snabbt svar",profile.answer),
    svDefinition("definition",profile.h1,profile.definition),
    svText("beslutslage","Beslutet som guiden ska stödja",profile.decision,planningAngles[index%planningAngles.length],"Definiera först vilket beslut som ska fattas, vem som godkänner det och vilket bevis som krävs. Då blir sökningen efter leverantörer, prover och offerter betydligt mer fokuserad."),
    svText("arbetsmetod","Rekommenderad arbetsmetod",profile.method,"Arbeta från behov till specifikation och därefter till leverantörsbevis. Om ordningen vänds riskerar köparen att låta den första katalogen bestämma kraven. Varje öppet val skrivs som fråga med ägare och sista beslutsdatum.","Frys inte fler egenskaper än verksamheten behöver, men lämna inte kritiska gränssnitt öppna. Mått, vikt, material, kompatibilitet, märkning och packning påverkar ofta både funktion och kostnad."),
    svTable("beslutstabell","Beslutstabell",["Område","Fråga","Bevis före beslut"],[["Användning","Vem använder eller säljer?","Målgrupp, miljö och belastning"],["Produkt","Vad ska levereras?","Artikel, version, mått och material"],["Kvalitet","Vad får avvika?","Mätmetod, tolerans och urval"],["Varumärke","Vad ska kunden se?","Artwork, prov, etikett och kartong"],["Logistik","Hur når varan lagret?","Packlista, bruttovikt, volym och Incoterm"]]),
    svText("bevis","Vilka bevis är användbara?",profile.evidence,"Bra bevis är kopplat till den aktuella produkten, har datum och version och kan kontrolleras av en annan person. En katalog, allmän certifikatbild eller obekräftad säljuppgift kan väcka en fråga men ska inte ensam stänga den.","Spara godkända filer och fysiska referenser så att nästa order kan jämföras. När material, verktyg, underleverantör eller process ändras ska leverantören flagga ändringen innan produktionen fortsätter."),
    svText("tillverkarkunskap","Förstahandskunskap från tillverkning","PowerBaseFits erfarenhet är att sena problem ofta börjar som små otydligheter i RFQ:n: en enhet saknas, ett foto används som ritning, logometoden är inte vald eller kartongen antas ingå. Därför separeras produktkrav, prov, kontroll och logistik i offertflödet.","Ett prov visar att en version kan tillverkas. Produktionskontroll visar om partiet upprepar den. Slutinspektion visar vad som är färdigt för leverans. Dessa tre nivåer ska inte blandas ihop.",planningAngles[(index+2)%planningAngles.length]),
    svText("jamforelse","Jämförelse och avvägning",profile.comparison,"Skapa en jämförelsematris där varje alternativ bedöms mot samma användning och samma kommersiella omfattning. Notera när ett alternativ kräver annan förvaring, reservdel, emballage eller utbildning.","Välj inte automatiskt högsta specifikation. Rätt nivå ger tillräcklig funktion, verifiering och livscykelvärde utan onödig kostnad eller artikelkomplexitet."),
    svText("risker","Vanliga risker och hur de minskas",profile.risk,"Gör varje större risk synlig i en risklista med sannolikhet, konsekvens, förebyggande åtgärd och ansvarig. Koppla sedan riskerna till prov, kontroll eller kommersiellt villkor.","Om leverantören föreslår en ändring ska effekten på funktion, utseende, MOQ, pris, ledtid, QC och återbeställning bedömas innan godkännande. Tyst substitution är inte en ändringsprocess."),
    ...guideDeepDive(profile),
    svText("leverantorsmote","Frågor att ta med till leverantörsmötet",`Be leverantören förklara vilket underlag som behövs för att lösa just ${profile.keyword}, vem som äger den tekniska frågan och när ett svar kan verifieras. Fråga också vilka delar som är standard, vilka som kräver kundanpassning och vilka antaganden som ligger bakom pris och ledtid.`,"Gå igenom kravlistan rad för rad och markera accepterat, avvikande eller öppet. För varje öppen punkt bestäms nästa bevis: ritning, materialuppgift, mätning, prov, packningsförslag eller kommersiellt klarläggande. Sammanfatta mötet i samma dokument och undvik parallella instruktioner i privata chattar.","Avsluta med ansvar, datum och stoppunkter före prov, materialinköp, serieproduktion, inspektion och lastning. Leverantörens snabbhet är värdefull först när svaret kan kopplas till rätt artikelversion. En fråga som saknar bevis ska förbli öppen även om båda parter tror att de menar samma sak."),
    svText("svensk-import","Svensk import och marknadsansvar","När varor importeras från ett land utanför EU behöver den svenska aktören verifiera varukod, tullvärde, tull, importmoms och eventuella restriktioner. Produkt- och kemikalieansvar kan bero på material, användning och hur varan säljs.","PowerBaseFit kan lämna produktspecifik leverantörsinformation enligt överenskommelse, men köparen ska bedöma vilka dokument och tester som krävs för den svenska marknaden. Använd Tullverket, Kemikalieinspektionen och kvalificerad rådgivning för aktuella besked."),
    svChecklist("checklista","Praktisk inköpschecklista",["Beskriv målgrupp och användningsmiljö","Lista artikel och antal per variant","Skriv mått, vikt, material och toleranser","Definiera provtyp och godkännare","Välj logo, färg, etikett och kartong","Bestäm kontrollpunkter och stickprov","Begär netto- och bruttovikt samt volym","Jämför samma Incoterm och leveranspunkt","Verifiera svenskt import- och produktansvar","Arkivera versioner för återbeställning"]),
    svText("nasta-steg","Nästa steg i inköpet","Använd checklistan för att skapa en kort brief eller RFQ. Skicka den tillsammans med artikelreferenser, volym och destination. PowerBaseFit markerar frågor som påverkar genomförbarhet, MOQ, pris, prov, inspektion eller leverans.","Nästa steg är inte alltid en offert. Om kritiska krav saknas kan ett tekniskt klargörande, materialalternativ eller provplan ge ett bättre beslut och spara tid längre fram."),
  ];
  return {locale:"sv",translationStatus:"localized",reviewStatus:"approved",publishStatus:"published",slug,publicPath:profile.path,title:profile.title,description:profile.description,h1:profile.h1,body,faq:[{id:"faq-1",question:`Vad är första steget för ${profile.keyword}?`,answer:`Börja med användning, målgrupp och vilket beslut som ska fattas. Skriv därefter produkt, volym och obligatoriska krav innan leverantör eller pris jämförs.`},{id:"faq-2",question:"Vilka uppgifter ska stå i en B2B-förfrågan?",answer:"Ange artikel, varianter, antal, material, vikt eller mått, toleranser, kundanpassning, emballage, destination, Incoterm, prov och önskad kontroll."},{id:"faq-3",question:"Räcker ett produktprov som kvalitetsbevis?",answer:"Nej. Provet blir referens för en version, men partiets jämnhet måste verifieras genom kontroll under eller efter produktion enligt avtalat urval."},{id:"faq-4",question:"När behövs tredjepartsinspektion?",answer:"Det beror på ordervärde, produktens risk, tidigare erfarenhet och köparens interna krav. Kriterier och åtkomst avtalas innan inspektionen bokas."},{id:"faq-5",question:"Vem ansvarar för svenska importkrav?",answer:"Den svenska importören och andra ekonomiska aktörer bedömer sina skyldigheter. Leverantörsdata är underlag, men ersätter inte aktuell juridisk, tull- eller produktsäkerhetsbedömning."}],author:swedishEditorialAuthor,reviewedBy:swedishTechnicalReviewer,schemaData:{brand:"PowerBaseFit",manufacturer:"PowerBaseFit",category:"B2B-inköpsguide",specifications:[{name:"Huvudämne",value:profile.keyword},{name:"Målgrupp",value:"Gymägare, distributörer, importörer och fitnessvarumärken"}],breadcrumbs:[{name:"Start",path:"/sv"},{name:"Kunskapsbank",path:"/sv/blogg"},{name:profile.h1,path:profile.path}],extra:{primaryKeyword:profile.keyword,searchIntent:"Informativ B2B-research med kommersiell nästa åtgärd"}},images,internalLinks:[...profile.links.map(([targetContentId,label])=>({targetContentId,label})),{targetContentId:"products-hub",label:"Se alla produkter"},{targetContentId:"oem-private-label",label:"OEM och eget varumärke"}],canonicalData:{mode:"self"},hreflangData:{include:true},updatedAt:"2026-07-20T12:00:00.000Z",publishedAt:"2026-07-20T12:00:00.000Z",version:1};
}
